public int[] fix45(int[] nums) {
    int[] result = new int[nums.length];
    int index = 0;
    int fiveIndex = 0;

    // Find all 5's indices
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 5) {
            result[fiveIndex++] = 5;
        }
    }

    fiveIndex = 0;

    // Place 4's and 5's in correct positions
    for (int i = 0; i < nums.length; i++) {
        if (nums[i] == 4) {
            result[index++] = 4;
            result[index++] = result[fiveIndex++];
        } else if (nums[i] != 5) {
            result[index++] = nums[i];
        }
    }

    return result;
}

